const payload = $input.first().json;

// Only process 'published' release events
const action = payload.action || '';
if (action !== 'published') {
  return [];
}

const release = payload.release || {};
const repo    = payload.repository || {};

const rawBody   = release.body || '';
const version   = release.tag_name || 'v0.0.0';
const releaseName = release.name || version;
const releaseUrl  = release.html_url || '';
const author      = release.author?.login || 'Team';
const publishedAt = release.published_at || new Date().toISOString();
const repoName    = repo.full_name || repo.name || 'Product';

// Parse changelog markdown into categories
const lines = rawBody.split('\n').map(l => l.trim()).filter(Boolean);
const features    = [];
const fixes       = [];
const improvements = [];
const other       = [];

let currentSection = 'other';
for (const line of lines) {
  const lower = line.toLowerCase();
  if (lower.includes('## feat') || lower.includes('### feat') || lower.includes('## new'))     { currentSection = 'features'; continue; }
  if (lower.includes('## fix')  || lower.includes('### fix')  || lower.includes('## bug'))     { currentSection = 'fixes'; continue; }
  if (lower.includes('## impr') || lower.includes('### impr') || lower.includes('## change'))  { currentSection = 'improvements'; continue; }
  if (line.startsWith('-') || line.startsWith('*') || line.startsWith('•')) {
    const clean = line.replace(/^[-*•]\s*/, '').trim();
    if (!clean) continue;
    if (currentSection === 'features')     features.push(clean);
    else if (currentSection === 'fixes')   fixes.push(clean);
    else if (currentSection === 'improvements') improvements.push(clean);
    else other.push(clean);
  }
}

// Plain text version for TTS script base
const plainChangelog = rawBody
  .replace(/#{1,6}\s*/g, '')
  .replace(/[*_`]/g, '')
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  .replace(/\n{3,}/g, '\n\n')
  .trim()
  .substring(0, 2000);

const releaseDate = new Date(publishedAt).toLocaleDateString('en-US', {
  weekday: 'long', year: 'numeric', month: 'long', day: 'numeric'
});

return [{
  json: {
    version,
    releaseName,
    releaseUrl,
    author,
    publishedAt,
    releaseDate,
    repoName,
    plainChangelog,
    features,
    fixes,
    improvements,
    other,
    totalChanges: features.length + fixes.length + improvements.length + other.length
  }
}];

const notionResp  = $input.first().json;
const releaseData = $('Code — Parse & Categorise Release Notes').item.json;

// Extract richer Notion content if page found
let notionSummary = '';
let notionPageId  = '';
let audioAlreadyPublished = false;

if (notionResp && notionResp.id) {
  notionPageId = notionResp.id;

  // Extract plain text from Notion title property
  const titleProp = notionResp.properties?.Name?.title ||
                    notionResp.properties?.Title?.title || [];
  const titleText = titleProp.map(t => t.plain_text || '').join('');

  // Check if audio already published
  const audioStatus = notionResp.properties?.AudioStatus?.select?.name || '';
  if (audioStatus === 'Published') {
    audioAlreadyPublished = true;
  }

  // Extract rich text summary
  const summaryProp = notionResp.properties?.Summary?.rich_text || [];
  notionSummary = summaryProp.map(t => t.plain_text || '').join('').trim();
}

if (audioAlreadyPublished) {
  // Return empty to stop processing
  return [];
}

return [{
  json: {
    ...releaseData,
    notionPageId,
    notionSummary: notionSummary || releaseData.plainChangelog.substring(0, 300)
  }
}];

// Store the spoken script text for later use before binary overwrites context
const aiResp      = $('OpenAI — Write Podcast-Style Spoken Script').item.json;
const releaseData = $('Code — Merge Notion Context + Release Data').item.json;

const spokenScript = aiResp?.choices?.[0]?.message?.content || '';

// Pass-through: binary data stays in item, we just annotate json
return [{
  json: {
    ...releaseData,
    spokenScript
  },
  binary: $input.first().binary
}];

const uploadResp  = $input.first().json;
const releaseData = $('Code — Store Script Text Before Upload').item.json;

const audioUrl =
  uploadResp?.url ??
  uploadResp?.data?.url ??
  uploadResp?.file?.url ??
  uploadResp?.link ??
  '';

return [{
  json: {
    ...releaseData,
    audioUrl
  }
}];
